	/// Provides extension methods for adding <see cref="T:Microsoft.Agents.AI.AIContextProvider" /> support to <see cref="T:Microsoft.Extensions.AI.ChatClientBuilder" /> instances.
	/// </summary>
	public static class AIContextProviderChatClientBuilderExtensions
	{
		/// <summary>
		/// Adds one or more <see cref="T:Microsoft.Agents.AI.AIContextProvider" /> instances to the chat client pipeline, enabling context enrichment
		/// (messages, tools, and instructions) for any <see cref="T:Microsoft.Extensions.AI.IChatClient" />.
		/// </summary>
		/// <param name="builder">The <see cref="T:Microsoft.Extensions.AI.ChatClientBuilder" /> to which the providers will be added.</param>
		/// <param name="providers">
		/// The <see cref="T:Microsoft.Agents.AI.AIContextProvider" /> instances to invoke before and after each chat client call.
		/// Providers are called in sequence, with each receiving the accumulated context from the previous provider.
		/// </param>
		/// <returns>The <see cref="T:Microsoft.Extensions.AI.ChatClientBuilder" /> with the providers added, enabling method chaining.</returns>
		/// <exception cref="T:System.ArgumentNullException"><paramref name="builder" /> or <paramref name="providers" /> is <see langword="null" />.</exception>
		/// <exception cref="T:System.ArgumentException"><paramref name="providers" /> is empty.</exception>
		/// <remarks>
		/// <para>
		/// This method wraps the inner chat client with a decorator that calls each provider's
		/// <see cref="M:Microsoft.Agents.AI.AIContextProvider.InvokingAsync(Microsoft.Agents.AI.AIContextProvider.InvokingContext,System.Threading.CancellationToken)" /> in sequence before the inner client is called,
		/// and calls <see cref="M:Microsoft.Agents.AI.AIContextProvider.InvokedAsync(Microsoft.Agents.AI.AIContextProvider.InvokedContext,System.Threading.CancellationToken)" /> on each provider after the inner client completes.
		/// </para>
		/// <para>
		/// The chat client must be used within the context of a running <see cref="T:Microsoft.Agents.AI.AIAgent" />. The agent and session
		/// are retrieved from <see cref="P:Microsoft.Agents.AI.AIAgent.CurrentRunContext" />. An <see cref="T:System.InvalidOperationException" />
		/// is thrown at invocation time if no run context is available.
		/// </para>
		/// </remarks>
		public static ChatClientBuilder UseAIContextProviders(this ChatClientBuilder builder, params AIContextProvider[] providers)
		{
